30	template<typename T>
31	void ViTTransformer<T>::initialize()
32	{
33	    FT_LOG_DEBUG("img_size: %lu, patch_size:%lu\n"
34	                 "batch_size:%lu, chn_num  : %lu\n"
35	                 "seq_len   :%lu, embed_dim: %lu\n"
36	                 "head_num  :%lu, head_dim : %lu\n"
37	                 "inter_size:%lu, num_layer: %lu\n"
38	                 "att_type  : %d, \n",
39	                 img_size_,
40	                 patch_size_,
41	                 max_batch_size_,
42	                 chn_num_,
43	                 max_seq_len_,
44	                 embed_dim_,
45	                 head_num_,
46	                 head_dim_,
47	                 inter_size_,
48	                 num_layer_,
49	                 int(attention_type_));
50	    if (img_size_ % patch_size_ != 0) {
51	        std::ostringstream buffer;
52	        buffer << "[FT][ERROR] IMG size & PITCH size mismatch. " << img_size_ << " % " << patch_size_ << " !=0 \n";
53	        throw std::runtime_error(buffer.str());
54	    }
55	
56	    if (head_num_ * head_dim_ != embed_dim_) {
57	        std::ostringstream buffer;
58	        buffer << "[FT][ERROR] Embed size and head number mismatch. Embed_dim=" << embed_dim_
59	               << "; head_num*head_dim = "
60	               << "(" << head_num_ << "*" << head_dim_ << ")=" << head_num_ * head_dim_ << std::endl;
61	        throw std::runtime_error(buffer.str());
62	    }
63	
64	    max_seq_len_ = request_seq_len_;
65	    if ((attention_type_ == AttentionType::FUSED_MHA) && std::is_same<T, half>::value == true) {
66	
67	        attention_layer_ = new FusedAttentionLayer<T>(max_batch_size_,
68	                                                      max_seq_len_,
69	                                                      head_num_,
70	                                                      head_dim_,
71	                                                      head_num_ * head_dim_,
72	                                                      sm_,
73	                                                      q_scaling_,
74	                                                      stream_,
75	                                                      cublas_wrapper_,
76	                                                      allocator_,
77	                                                      is_free_buffer_after_forward_,
78	                                                      false);
79	    }
80	    else if (attention_type_ == AttentionType::UNFUSED_MHA) {
81	        if (request_seq_len_ % 8 != 0 && std::is_same<half, T>::value) {
82	            max_seq_len_ = (request_seq_len_ + 7) / 8 * 8;
83	            FT_LOG_DEBUG("Request sequence length(%lu) is odd with unfused mha. Padding to %lu\n",
84	                         request_seq_len_,
85	                         max_seq_len_);
86	        }
87	        attention_layer_ = new UnfusedAttentionLayer<T>(max_batch_size_,
88	                                                        max_seq_len_,
89	                                                        head_num_,
90	                                                        head_dim_,
91	                                                        q_scaling_,
92	                                                        stream_,
93	                                                        cublas_wrapper_,
94	                                                        allocator_,
95	                                                        is_free_buffer_after_forward_,
96	                                                        false);
97	    }
98	    else {
99	        throw std::runtime_error(std::string("[FT][ERROR] Invalid attention type or sequence length\n"));
100	    }
101	
102	    ffn_layer_ = new GeluFfnLayer<T>(max_batch_size_,
103	                                     max_seq_len_,
104	                                     head_num_,
105	                                     head_dim_,
106	                                     0,  // expert_num
107	                                     inter_size_,
108	                                     stream_,
109	                                     cublas_wrapper_,
110	                                     allocator_,
111	                                     is_free_buffer_after_forward_,
112	                                     false);
113	}
