115	template<typename T>
116	ViTTransformer<T>::ViTTransformer(size_t           max_batch_size,
117	                                  size_t           img_size,
118	                                  size_t           chn_num,
119	                                  size_t           patch_size,
120	                                  size_t           embed_dim,
121	                                  size_t           head_num,
122	                                  size_t           inter_size,
123	                                  size_t           num_layer,
124	                                  bool             with_cls_token,
125	                                  int              sm,
126	                                  float            q_scaling,
127	                                  cudaStream_t     stream,
128	                                  cudnnHandle_t    cudnn_handle,
129	                                  cublasMMWrapper* cublas_wrapper,
130	                                  IAllocator*      allocator,
131	                                  bool             is_free_buffer_after_forward,
132	                                  AttentionType    attention_type):
133	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward),
134	    max_batch_size_(max_batch_size),
135	    img_size_(img_size),
136	    chn_num_(chn_num),
137	    patch_size_(patch_size),
138	    request_seq_len_(img_size * img_size / patch_size / patch_size + (with_cls_token ? 1 : 0)),
139	    max_seq_len_(0),
140	    embed_dim_(embed_dim),
141	    head_num_(head_num),
142	    head_dim_(embed_dim / head_num),
143	    inter_size_(inter_size),
144	    num_layer_(num_layer),
145	    with_cls_token_(with_cls_token),
146	    sm_(sm),
147	    q_scaling_(q_scaling),
148	    attention_type_(attention_type),
149	    cudnn_handle_(cudnn_handle)
150	{
151	    initialize();
152	}
