185	template<typename T>
186	void ViTTransformer<T>::allocateBuffer()
187	{
188	    if (is_allocate_buffer_ == false) {
189	        embed_buf_1_ =
190	            (T*)allocator_->reMalloc(embed_buf_1_, sizeof(T) * max_batch_size_ * max_seq_len_ * embed_dim_, false);
191	        embed_buf_2_ =
192	            (T*)allocator_->reMalloc(embed_buf_2_, sizeof(T) * max_batch_size_ * max_seq_len_ * embed_dim_, false);
193	        embed_buf_3_ =
194	            (T*)allocator_->reMalloc(embed_buf_3_, sizeof(T) * max_batch_size_ * max_seq_len_ * embed_dim_, false);
195	        mask_buf_ =
196	            (T*)allocator_->reMalloc(mask_buf_, sizeof(T) * max_batch_size_ * max_seq_len_ * max_seq_len_, false);
197	        padding_offset_ =
198	            (int*)allocator_->reMalloc(padding_offset_, sizeof(int) * max_batch_size_ * max_seq_len_, false);
199	        h_pinned_token_num_ptr_ = (size_t*)allocator_->reMalloc(h_pinned_token_num_ptr_, sizeof(size_t), true, true);
200	
201	        trt_mha_padding_offset_ =
202	            (int*)allocator_->reMalloc(trt_mha_padding_offset_, sizeof(int) * (2 * max_batch_size_ + 1), false);
203	        seq_len_vec_ = (int*)allocator_->reMalloc(seq_len_vec_, sizeof(int) * max_batch_size_, false);
204	
205	        setSeqLenVec(max_batch_size_);
206	        setDefaultMask(max_batch_size_);
207	        setDefaultPaddingOffset(max_batch_size_);
208	
209	        is_allocate_buffer_ = true;
210	    }
211	}
212	
213	#define REMALLOC(var, size)                                                                                            \
214	    {                                                                                                                  \
215	        var = (decltype(var))allocator_->reMalloc(var, size, false);                                                   \
216	        FT_LOG_DEBUG("ReMalloc %s, ptr:%x, size:%lu", #var, var, size);                                                \
217	    }
218	
219	template<typename T>
220	void ViTTransformer<T>::allocateBuffer(size_t batch_size)
221	{
222	    if (is_allocate_buffer_ && batch_size <= max_batch_size_) {
223	        return;
224	    }
225	
226	    batch_size = batch_size > max_batch_size_ ? batch_size : max_batch_size_;
227	    REMALLOC(embed_buf_1_, sizeof(T) * batch_size * max_seq_len_ * embed_dim_);
228	    REMALLOC(embed_buf_2_, sizeof(T) * batch_size * max_seq_len_ * embed_dim_);
229	    REMALLOC(embed_buf_3_, sizeof(T) * batch_size * max_seq_len_ * embed_dim_);
230	    REMALLOC(mask_buf_, sizeof(T) * batch_size * max_seq_len_ * max_seq_len_);
231	    REMALLOC(padding_offset_, sizeof(int) * batch_size * max_seq_len_);
232	    h_pinned_token_num_ptr_ = (size_t*)allocator_->reMalloc(h_pinned_token_num_ptr_, sizeof(size_t), true, true);
233	    REMALLOC(trt_mha_padding_offset_, sizeof(int) * (2 * batch_size + 1));
234	    REMALLOC(seq_len_vec_, sizeof(int) * batch_size);
235	    resetBatch(batch_size);
236	    setSeqLenVec(batch_size);
237	    setDefaultPaddingOffset(batch_size);
238	    setDefaultMask(batch_size);
239	
240	    is_allocate_buffer_ = true;
241	}
242	
243	template<typename T>
244	void ViTTransformer<T>::freeBuffer()
245	{
246	    if (is_allocate_buffer_) {
247	        allocator_->free((void**)(&embed_buf_1_));
248	        allocator_->free((void**)(&embed_buf_2_));
249	        allocator_->free((void**)(&embed_buf_3_));
250	        allocator_->free((void**)(&mask_buf_));
251	        allocator_->free((void**)(&trt_mha_padding_offset_));
252	        allocator_->free((void**)(&seq_len_vec_));
253	        allocator_->free((void**)(&padding_offset_));
254	        allocator_->free((void**)(&h_pinned_token_num_ptr_), true);
255	        is_allocate_buffer_ = false;
256	    }
257	}
