259	template<typename T>
260	void ViTTransformer<T>::forward(std::vector<Tensor>*       output_tensors,
261	                                const std::vector<Tensor>* input_tensors,
262	                                const ViTWeight<T>*        weights)
263	{
264	    // input_tensors:
265	    //      input_img, BCHW [batch, chn_num, img_size, img_size]
266	    // output tensors:
267	    //      output feature_map [batch, seq_len, embed_dim]
268	
269	    const size_t input_batch_size = input_tensors->at(0).shape[0];
270	    const size_t input_chn_num    = input_tensors->at(0).shape[1];
271	    const size_t input_img_size   = input_tensors->at(0).shape[2];
272	    const size_t patch_resol      = input_img_size / patch_size_;
273	    size_t       seq_len          = patch_resol * patch_resol + (with_cls_token_ ? 1 : 0);
274	    const bool   need_padding =
275	        (attention_type_ == AttentionType::UNFUSED_MHA && seq_len % 8 != 0 && std::is_same<half, T>::value);
276	
277	    FT_CHECK(input_img_size == img_size_);
278	    FT_CHECK(seq_len == request_seq_len_);
279	    FT_CHECK(input_tensors->size() == 1);
280	    FT_CHECK(input_tensors->at(0).shape.size() == 4);
281	    FT_CHECK(output_tensors->size() == 1);
282	    FT_CHECK(output_tensors->at(0).shape.size() == 3);
283	    allocateBuffer(input_batch_size);
284	
285	    const T* input             = input_tensors->at(0).getPtr<const T>();
286	    T*       output            = output_tensors->at(0).getPtr<T>();
287	    T*       encoder_input_ptr = embed_buf_1_;
288	
289	    // preprocess (patches embedding, concat class embed and add pos embed)
290	    patchEmbed(need_padding ? embed_buf_2_ : encoder_input_ptr,
291	               input,
292	               weights->pre_encoder_conv_weights.kernel,
293	               weights->pre_encoder_conv_weights.bias,
294	               weights->pre_transform_embeds.class_embed,
295	               weights->pre_transform_embeds.position_embed,
296	               input_batch_size,
297	               input_img_size,
298	               patch_size_,
299	               seq_len,
300	               input_chn_num,
301	               embed_dim_);
302	
303	    DataType data_type = getTensorType<T>();
304	
305	    size_t h_token_num = input_batch_size * seq_len;
306	    // get offsets
307	    Tensor* offset_tensor_ptr;
308	    if (attention_type_ == AttentionType::FUSED_MHA) {
309	        invokeGetTrtPaddingOffset(trt_mha_padding_offset_, seq_len_vec_, input_batch_size, stream_);
310	        offset_tensor_ptr =
311	            new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{input_batch_size + 1}, trt_mha_padding_offset_);
312	    }
313	    else {
314	        offset_tensor_ptr = new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{0}, nullptr);
315	        if (need_padding) {
316	            seq_len     = (seq_len + 7) / 8 * 8;
317	            h_token_num = seq_len * input_batch_size;
318	            cudaMemsetAsync(encoder_input_ptr, 0, sizeof(T) * input_batch_size * seq_len * embed_dim_, stream_);
319	            invokeRebuildPadding(
320	                encoder_input_ptr, embed_buf_2_, padding_offset_, nopad_token_num_, head_num_ * head_dim_, stream_);
321	        }
322	    }
323	
324	    T* from_buf        = encoder_input_ptr;
325	    T* norm_out_buf    = embed_buf_2_;
326	    T* attn_out_buf    = embed_buf_3_;
327	    T* encoder_out_buf = from_buf;
328	
329	    for (uint i = 0; i < num_layer_; i++) {
330	
331	        invokeGeneralLayerNorm(norm_out_buf,
332	                               from_buf,
333	                               weights->vit_layer_weights[i].attn_layernorm_weights.gamma,
334	                               weights->vit_layer_weights[i].attn_layernorm_weights.beta,
335	                               layernorm_eps_,
336	                               h_token_num,
337	                               embed_dim_,
338	                               (float*)nullptr,
339	                               0,
340	                               stream_);
341	        // Attention
342	        {
343	
344	            TensorMap attn_input_tensors{
345	                {"input_query",
346	                 Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, embed_dim_}, norm_out_buf}},
347	                {"attention_mask",
348	                 Tensor{MEMORY_GPU, data_type, std::vector<size_t>{input_batch_size, 1, seq_len, seq_len}, mask_buf_}}};
349	            attn_input_tensors.insertIfValid("padding_offset", *offset_tensor_ptr);
350	
351	            TensorMap attn_output_tensors{
352	                {"hidden_features",
353	                 Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, embed_dim_}, attn_out_buf}}};
354	
355	            attention_layer_->forward(
356	                &attn_output_tensors, &attn_input_tensors, &weights->vit_layer_weights[i].attention_weights);
357	        }
358	
359	        invokeGeneralAddBiasResidualPreLayerNorm(
360	            from_buf,
361	            norm_out_buf,
362	            from_buf,
363	            attn_out_buf,
364	            weights->vit_layer_weights[i].ffn_layernorm_weights.gamma,
365	            weights->vit_layer_weights[i].ffn_layernorm_weights.beta,
366	            weights->vit_layer_weights[i].attention_weights.attention_output_weight.bias,
367	            layernorm_eps_,
368	            h_token_num,
369	            embed_dim_,
370	            (float*)nullptr,
371	            (float*)nullptr,
372	            (float*)nullptr,
373	            (float*)nullptr,
374	            0,
375	            stream_);
376	
377	        // FFN
378	        {
379	            TensorMap ffn_input_tensors(
380	                {{"ffn_input",
381	                  Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, embed_dim_}, norm_out_buf}}});
382	            TensorMap ffn_output_tensors(
383	                {{"ffn_output",
384	                  Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, embed_dim_}, attn_out_buf}}});
385	            ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &weights->vit_layer_weights[i].ffn_weights);
386	        }
387	
388	        invokeAddBiasResidual(from_buf,
389	                              attn_out_buf,
390	                              weights->vit_layer_weights[i].ffn_weights.output_weight.bias,
391	                              h_token_num,
392	                              embed_dim_,
393	                              stream_);
394	
395	        sync_check_cuda_error();
396	    }
397	
398	    invokeGeneralLayerNorm(need_padding ? norm_out_buf : output,
399	                           from_buf,
400	                           weights->post_transformer_layernorm_weights.gamma,
401	                           weights->post_transformer_layernorm_weights.beta,
402	                           layernorm_eps_,
403	                           h_token_num,
404	                           embed_dim_,
405	                           (float*)nullptr,
406	                           0,
407	                           stream_);
408	
409	    if (need_padding) {
410	        invokeRemovePadding(output, norm_out_buf, padding_offset_, nopad_token_num_, head_num_ * head_dim_, stream_);
411	    }
412	
413	    if (is_free_buffer_after_forward_ == true) {
414	        freeBuffer();
415	    }
416	    sync_check_cuda_error();
417	
418	    SAFE_FREE(offset_tensor_ptr);
419	}
