421	template<typename T>
422	bool ViTTransformer<T>::resetBatch(size_t batch_size)
423	{
424	    if (max_batch_size_ < batch_size) {
425	        max_batch_size_ = batch_size;
426	    }
427	
428	    return true;
429	}
430	
431	template<typename T>
432	bool ViTTransformer<T>::setSeqLenVec(size_t batch_size)
433	{
434	    int* seq_len_vec = new int[batch_size];
435	    for (int i = 0; i < batch_size; i++) {
436	        seq_len_vec[i] = request_seq_len_;
437	    }
438	    cudaMemcpy(seq_len_vec_, seq_len_vec, sizeof(int) * batch_size, cudaMemcpyHostToDevice);
439	    delete seq_len_vec;
440	    return true;
441	}
442	
443	template<typename T>
444	void ViTTransformer<T>::setDefaultMask(size_t batch_size)
445	{
446	    invokeBuildEncoderAttentionMask(mask_buf_, seq_len_vec_, batch_size, max_seq_len_, stream_);
447	}
448	
449	template<typename T>
450	void ViTTransformer<T>::setDefaultPaddingOffset(size_t batch_size)
451	{
452	    invokeGetPaddingOffset(
453	        h_pinned_token_num_ptr_, &nopad_token_num_, padding_offset_, seq_len_vec_, batch_size, max_seq_len_, stream_);
454	}
455	
456	template<typename T>
457	void ViTTransformer<T>::patchEmbed(T*        output,
458	                                   const T*  input,
459	                                   const T*  kernel,
460	                                   const T*  bias,
461	                                   const T*  cls_embed,
462	                                   const T*  pos_embed,
463	                                   const int batch,
464	                                   const int img_size,
465	                                   const int patch_size,
466	                                   const int seq_len,
467	                                   const int in_chans,
468	                                   const int embed_dim)
469	{
470	    T* tmp_buf = with_cls_token_ ? (output == embed_buf_1_ ? embed_buf_2_ : embed_buf_1_) : output;
471	
472	    conv2d(
473	        tmp_buf, input, kernel, batch, img_size, img_size, in_chans, embed_dim, patch_size, patch_size, cudnn_handle_);
474	    int n = embed_dim;
475	    int s = seq_len;
476	    int m = batch * s;
477	    if (with_cls_token_) {
478	        FT_CHECK(cls_embed != nullptr);
479	        invokeAddBiasConcatClsTokenAddPosEmbed(tmp_buf, output, bias, cls_embed, pos_embed, m, n, s, stream_);
480	    }
481	    else {
482	        invokeAddBiasAddPosEmbed(tmp_buf, bias, pos_embed, m, n, s * n, stream_);
483	    }
484	}
