160	    //      input_query [batch, input_resolution, input_resolution, dim]
161	    //      additional_params [4] {basic_layer_depth, number_of_head, do_patch_merge, sm}
162	    // output_tensors:
163	    //      hidden_features [batch, output_resolution, output_resolution, output_dim]
164	
165	    T*        output_tensor     = output_tensors->getPtr<T>("hidden_features");
166	    T*        from_tensor       = input_tensors->getPtr<T>("input_query");
