193	                                                 block_output_ + (i % 2) * block_output_size}}};
194	            shift_size                         = (i % 2 == 0) ? 0 : (window_size_ / 2);
195	            int       additional_parameters[3] = {num_head, shift_size, sm};
196	            TensorMap tmp_input_tensors{
197	                {"input_query",
198	                 Tensor{MEMORY_GPU,
199	                        data_type,
200	                        std::vector<size_t>{batch, input_resolution, input_resolution, dim},
201	                        i == 0 ? from_tensor : block_output_ + ((i - 1) % 2) * block_output_size}},
202	                {"attention_mask",
203	                 Tensor{MEMORY_GPU,
204	                        TYPE_FP16,
