97	template<typename T>
98	void SwinTransformerBlock<T>::forward(TensorMap*                     output_tensors,
99	                                      TensorMap*                     input_tensors,
100	                                      SwinTransformerBlockWeight<T>& swin_block_weights)
101	{
102	    // input_tensors:
103	    //      input_query [batch, input_resolution, input_resolution, dim]
104	    //      attention_mask [window_num, window_len, window_len]
105	    //      trt_attention_mask  [window_num, trt_window_len, trt_window_len]
106	    //      additional_params [3] {number_of_head, shift_size, sm}
107	    // output_tensors:
108	    //      hidden_features [batch, input_resolution, input_resolution, dim]
109	
110	    T*         output             = output_tensors->getPtr<T>("hidden_features");
111	    T*         input              = input_tensors->getPtr<T>("input_query");
112	    int        batch              = input_tensors->at("input_query").shape[0];
113	    int        input_resolution   = input_tensors->at("input_query").shape[1];
114	    int        dim                = input_tensors->at("input_query").shape[3];
115	    T*         attention_mask     = input_tensors->getPtr<T>("attention_mask", nullptr);
116	    T*         trt_attention_mask = input_tensors->getPtr<T>("trt_attention_mask", nullptr);
117	    const int* additional_params  = input_tensors->getPtr<const int>("additional_params");
118	    const int  num_head           = additional_params[0];
119	    int        shift_size         = additional_params[1];
120	    const int  sm                 = additional_params[2];
121	    FT_CHECK(input_resolution == input_tensors->at("input_query").shape[2]);
122	
123	    int window_size_in_use = (input_resolution <= window_size_) ? input_resolution : window_size_;
124	    int window_len_in_use  = window_size_in_use * window_size_in_use;
125	    shift_size             = (input_resolution <= window_size_) ? 0 : shift_size;
126	    int window_num         = (input_resolution / window_size_in_use) * (input_resolution / window_size_in_use);
127	    int mlp_dim            = int(mlp_ratio_ * dim);
128	    allocateBuffer(batch, input_resolution, dim);
129	
130	    if (version_ == 2) {
131	        invokeShiftPartition(normed_shifted_input_,
132	                             input,
133	                             batch,
134	                             input_resolution,
135	                             input_resolution,
136	                             dim,
137	                             shift_size,
138	                             window_size_in_use,
139	                             stream_);
140	    }
141	    else if (version_ == 1) {
142	        invokeLayernormShiftPartition(normed_shifted_input_,
143	                                      input,
144	                                      swin_block_weights.attn_layernorm_weights.gamma,
145	                                      swin_block_weights.attn_layernorm_weights.beta,
146	                                      layernorm_eps_,
147	                                      batch,
148	                                      input_resolution,
149	                                      input_resolution,
150	                                      dim,
151	                                      shift_size,
152	                                      window_size_in_use,
153	                                      stream_);
154	    }
155	
156	    const size_t m                     = batch * input_resolution * input_resolution;
157	    const size_t n                     = dim;
158	    DataType     data_type             = getTensorType<T>();
159	    int       additional_parameters[7] = {batch, dim, input_resolution, num_head, shift_size, sm, window_size_in_use};
160	    TensorMap attn_output_tensors{
161	        {"hidden_features", Tensor{MEMORY_GPU, data_type, std::vector<size_t>{m, n}, attention_output_}}};
162	    TensorMap attn_input_tensors{
163	        {"input_query", Tensor{MEMORY_GPU, data_type, std::vector<size_t>{m, n}, normed_shifted_input_}},
164	        {"attention_mask",
165	         Tensor{MEMORY_GPU,
166	                data_type,
167	                std::vector<size_t>{(size_t)window_num, (size_t)window_len_in_use, (size_t)window_len_in_use},
168	                attention_mask}},
169	        {"trt_attention_mask",
170	         Tensor{MEMORY_GPU,
171	                data_type,
172	                std::vector<size_t>{(size_t)window_num, (size_t)window_len_in_use, (size_t)window_len_in_use},
173	                trt_attention_mask}},
