175	         Tensor{MEMORY_GPU,
176	                TYPE_FP16,
177	                std::vector<size_t>{(size_t)num_head, (size_t)window_len_in_use, (size_t)window_len_in_use},
178	                swin_block_weights.attention_relative_pos_bias}},
179	        {"trt_relative_position_bias",
180	         Tensor{MEMORY_GPU,
181	                data_type,
182	                std::vector<size_t>{(size_t)num_head, (size_t)window_len_in_use, (size_t)window_len_in_use},
183	                swin_block_weights.trt_relative_position_bias}},
184	        {"attn_logit_scale",
185	         Tensor{
186	             MEMORY_GPU, data_type, std::vector<size_t>{(size_t)num_head}, swin_block_weights.attention_logit_scale}},
187	        {"additional_params", Tensor{MEMORY_CPU, TYPE_INT32, {7}, additional_parameters}}};
188	
189	    atten_->forward(&attn_output_tensors, &attn_input_tensors, &swin_block_weights.attention_weights);
190	
191	    if (version_ == 2) {
192	        invokeAddBiasLayernormAddRes(attention_output_,
193	                                     input,
194	                                     swin_block_weights.attention_weights.attention_output_weight.bias,
195	                                     swin_block_weights.attn_layernorm_weights.gamma,
196	                                     swin_block_weights.attn_layernorm_weights.beta,
197	                                     layernorm_eps_,
198	                                     m,
199	                                     n,
200	                                     stream_);
201	    }
202	    else if (version_ == 1) {
203	        invokeGeneralAddBiasResidualPreLayerNorm(attention_output_,
204	                                                 normed_attn_out_buf_,
