235	                        swin_block_weights.ffn_weights.intermediate_weight.bias,
236	                        (const int*)nullptr,
237	                        (const T*)nullptr,
238	                        batch * input_resolution * input_resolution,
239	                        mlp_dim,
240	                        stream_);
241	
242	    cublas_wrapper_->Gemm(CUBLAS_OP_T,
243	                          CUBLAS_OP_N,
244	                          dim,
245	                          batch * input_resolution * input_resolution,
246	                          mlp_dim,
247	                          swin_block_weights.ffn_weights.output_weight.kernel,
248	                          mlp_dim,
249	                          mlp_buf_,
250	                          mlp_dim,
251	                          output,
252	                          dim);
253	
254	    if (version_ == 2) {
255	        invokeAddBiasLayernormAddRes(output,
256	                                     attention_output_,
257	                                     swin_block_weights.ffn_weights.output_weight.bias,
258	                                     swin_block_weights.ffn_layernorm_weights.gamma,
259	                                     swin_block_weights.ffn_layernorm_weights.beta,
