23	
24	// applied to half2 and bfloat162
25	template<typename T2>
26	__global__ void
27	shift_partition(T2* out_ptr, const T2* input_ptr, int batch, int H, int W, int n, int shift_size, int window_size)
28	{
29	    const int batch_offset       = blockIdx.z * gridDim.y * gridDim.x;
30	    const int bid                = batch_offset + blockIdx.y * gridDim.x + blockIdx.x;
31	    const int shifted_H_idx      = (shift_size != 0) ? ((blockIdx.y - shift_size + gridDim.y) % gridDim.y) : blockIdx.y;
32	    const int shifted_W_idx      = (shift_size != 0) ? ((blockIdx.x - shift_size + gridDim.x) % gridDim.x) : blockIdx.x;
33	    const int window_H_idx       = shifted_H_idx / window_size;
34	    const int window_W_idx       = shifted_W_idx / window_size;
35	    const int stride_of_window_H = W / window_size;
36	    const int window_idx         = window_H_idx * stride_of_window_H + window_W_idx;
37	    const int idx_in_window      = (shifted_H_idx % window_size) * window_size + (shifted_W_idx % window_size);
38	    const int output_bid         = batch_offset + window_idx * window_size * window_size + idx_in_window;
39	    int       tid                = threadIdx.x;
40	
41	    int id = bid * n + tid;
42	    if (tid < n) {
43	        out_ptr[output_bid * n + tid] = input_ptr[id];
44	    }
45	}
46	
47	// applied to float
48	template<>
49	__global__ void
50	shift_partition<float>(float* out, const float* input, int batch, int H, int W, int n, int shift_size, int window_size)
51	{
52	    int       tid                = threadIdx.x;
53	    const int batch_offset       = blockIdx.z * gridDim.y * gridDim.x;
54	    const int bid                = batch_offset + blockIdx.y * gridDim.x + blockIdx.x;
55	    const int shifted_H_idx      = (shift_size != 0) ? ((blockIdx.y - shift_size + gridDim.y) % gridDim.y) : blockIdx.y;
56	    const int shifted_W_idx      = (shift_size != 0) ? ((blockIdx.x - shift_size + gridDim.x) % gridDim.x) : blockIdx.x;
57	    const int window_H_idx       = shifted_H_idx / window_size;
58	    const int window_W_idx       = shifted_W_idx / window_size;
59	    const int stride_of_window_H = W / window_size;
60	    const int window_idx         = window_H_idx * stride_of_window_H + window_W_idx;
61	    const int idx_in_window      = (shifted_H_idx % window_size) * window_size + (shifted_W_idx % window_size);
62	    const int output_bid         = batch_offset + window_idx * window_size * window_size + idx_in_window;
63	    if (tid < n) {
64	        out[output_bid * n + tid] = (float)(__ldg(input + bid * n + tid));
65	    }
66	}
67	
68	// Applied to half2 and bfloat162
69	template<typename T2>
70	__global__ void shift_partition_v2(
71	    T2* out_ptr, const T2* __restrict input_ptr, int batch, int H, int W, int n, int shift_size, int window_size)
72	{
73	    using T1                     = typename TypeConverter<T2>::Type;  // half2 to half, bfloat162 to bfloat
74	    const int ite                = 4;
75	    const int tid                = threadIdx.x;
76	    const int batch_offset       = blockIdx.z * gridDim.y * gridDim.x;
77	    const int bid                = batch_offset + blockIdx.y * gridDim.x + blockIdx.x;
78	    const int shifted_H_idx      = (shift_size != 0) ? ((blockIdx.y - shift_size + gridDim.y) % gridDim.y) : blockIdx.y;
79	    const int shifted_W_idx      = (shift_size != 0) ? ((blockIdx.x - shift_size + gridDim.x) % gridDim.x) : blockIdx.x;
80	    const int window_H_idx       = shifted_H_idx / window_size;
81	    const int window_W_idx       = shifted_W_idx / window_size;
82	    const int stride_of_window_H = W / window_size;
83	    const int window_idx         = window_H_idx * stride_of_window_H + window_W_idx;
84	    const int idx_in_window      = (shifted_H_idx % window_size) * window_size + (shifted_W_idx % window_size);
85	    const int output_bid         = batch_offset + window_idx * window_size * window_size + idx_in_window;
86	    const int offset             = bid * n;
87	    const int output_offset      = output_bid * n;
88	#pragma unroll
89	    for (int i = 0; i < ite; i++) {
90	        int col_id = i * blockDim.x + tid;
91	        if (col_id < n) {
92	            out_ptr[output_offset + col_id] = ldg(input_ptr + offset + col_id);
93	        }
94	    }
95	}
96	
97	template<>
98	__global__ void shift_partition_v2<float>(
99	    float* out, const float* __restrict input, int batch, int H, int W, int n, int shift_size, int window_size)
100	{
101	    const int ite                = 4;
102	    const int tid                = threadIdx.x;
103	    const int batch_offset       = blockIdx.z * gridDim.y * gridDim.x;
104	    const int bid                = batch_offset + blockIdx.y * gridDim.x + blockIdx.x;
105	    const int shifted_H_idx      = (shift_size != 0) ? ((blockIdx.y - shift_size + gridDim.y) % gridDim.y) : blockIdx.y;
106	    const int shifted_W_idx      = (shift_size != 0) ? ((blockIdx.x - shift_size + gridDim.x) % gridDim.x) : blockIdx.x;
107	    const int window_H_idx       = shifted_H_idx / window_size;
108	    const int window_W_idx       = shifted_W_idx / window_size;
109	    const int stride_of_window_H = W / window_size;
110	    const int window_idx         = window_H_idx * stride_of_window_H + window_W_idx;
111	    const int idx_in_window      = (shifted_H_idx % window_size) * window_size + (shifted_W_idx % window_size);
112	    const int output_bid         = batch_offset + window_idx * window_size * window_size + idx_in_window;
113	    const int offset             = bid * n;
114	    const int output_offset      = output_bid * n;
115	
116	#pragma unroll
117	    for (int i = 0; i < ite; i++) {
118	        int col_id = i * blockDim.x + tid;
119	        if (col_id < n) {
120	            out[output_offset + col_id] = (float)(__ldg(input + offset + col_id));
121	        }
122	    }
123	}
124	
125	// Applied to half or Bfloat16
126	template<typename T>
127	void invokeShiftPartition(
128	    T* out, const T* input, int batch, int H, int W, int n, int shift_size, int window_size, cudaStream_t stream)
129	{
130	    dim3 grid(W, H, batch);
131	    int  blockSize = n / 2;
132	    blockSize      = (blockSize + 31) / 32 * 32;
133	
134	    using T2 = typename TypeConverter<T>::Type;  // bf162 or half2
135	
136	    if ((batch * H * W >= 512 && blockSize >= 768) || blockSize > 1024) {
137	        blockSize = ((blockSize / 4) + 31) / 32 * 32;
138	        shift_partition_v2<T2>
139	            <<<grid, blockSize, 0, stream>>>((T2*)out, (const T2*)input, batch, H, W, n / 2, shift_size, window_size);
140	    }
141	    else {
142	        shift_partition<T2>
143	            <<<grid, blockSize, 0, stream>>>((T2*)out, (const T2*)input, batch, H, W, n / 2, shift_size, window_size);
144	    }
145	}
146	
147	template<>
148	void invokeShiftPartition<float>(float*       out,
149	                                 const float* input,
150	                                 int          batch,
151	                                 int          H,
152	                                 int          W,
153	                                 int          n,
154	                                 int          shift_size,
155	                                 int          window_size,
156	                                 cudaStream_t stream)
157	{
